/**
 * EntityList Component
 * Displays a list of entities (mobiles/objects) with filtering and selection
 */

import React, { useState } from 'react';
import '../styles/EntityList.css';

export default function EntityList({ 
  entities, 
  entityType, 
  selected, 
  onSelect, 
  onCreateNew,
  onDelete 
}) {
  const [filter, setFilter] = useState('');

  const filtered = entities.filter(e =>
    e.vnum.toString().includes(filter) ||
    (e.keywords && e.keywords.toLowerCase().includes(filter.toLowerCase())) ||
    (e.short && e.short.toLowerCase().includes(filter.toLowerCase()))
  );

  return (
    <div className="entity-list">
      <div className="entity-list-header">
        <h3>{entityType}</h3>
        <button className="btn-primary" onClick={onCreateNew}>
          + New {entityType}
        </button>
      </div>

      <input
        type="text"
        placeholder={`Filter ${entityType}...`}
        value={filter}
        onChange={e => setFilter(e.target.value)}
        className="entity-filter"
      />

      <div className="entity-items">
        {filtered.length === 0 ? (
          <p className="empty-message">No {entityType} found</p>
        ) : (
          filtered.map(entity => (
            <div
              key={entity.vnum}
              className={`entity-item ${selected === entity.vnum ? 'selected' : ''}`}
              onClick={() => onSelect(entity.vnum)}
            >
              <div className="entity-vnum">{entity.vnum}</div>
              <div className="entity-info">
                <div className="entity-keywords">{entity.keywords || 'unnamed'}</div>
                <div className="entity-short">{entity.short || '-'}</div>
              </div>
              <button
                className="btn-delete"
                onClick={(e) => {
                  e.stopPropagation();
                  if (confirm(`Delete ${entityType} ${entity.vnum}?`)) {
                    onDelete(entity.vnum);
                  }
                }}
              >
                ✕
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );
}
